import { qpcLogo, qatarLogo, signatureLogo } from '../lib/logos'

const SEASON = '2025 / 2026'

const DESIGNATION_AR = {
  'Player': 'لاعب', 'Female Player': 'لاعبة',
  'Coach': 'مدرب', 'Female Coach': 'مدربة',
  'Referee': 'حكم', 'Female Referee': 'حكمة',
  'Admin Staff': 'جهاز إداري', 'Technical Staff': 'جهاز في',
  'Medical Staff': 'جهاز طبي',
  'Board Member': 'عضو مجلس إدارة', 'Female Board Member': 'عضوة مجلس إدارة',
  'Member': 'عضو', 'Female Member': 'عضوة',
  'Employee': 'موظف', 'Female Employee': 'موظفة',
  'Expert': 'خبير في',
}

const RESIDENCY_AR = {
  'Qatari Male': 'قطري', 'Qatari Female': 'قطرية',
  'Resident Male': 'مقيم', 'Resident Female': 'مقيمة',
  'Professional Male': 'محترف', 'Professional Female': 'محترفة',
  'Born in Qatar': 'مواليد قطر', 'Qatari Mother': 'أم قطرية',
}

// Inline base64 to avoid cross-origin issues
const SIG = 'data:image/jpeg;base64,'
const QPC = 'data:image/png;base64,'
const QATAR = 'data:image/png;base64,'

export function generateAthleteCard(athlete) {
  const desigAr  = DESIGNATION_AR[athlete.designation] || athlete.designation || 'لاعب'
  const residAr  = RESIDENCY_AR[athlete.residency_status] || athlete.residency_status || ''
  const photoSrc = athlete.photo_url || ''

  const html = `<!DOCTYPE html>
<html lang="ar">
<head>
<meta charset="UTF-8"/>
<title>${athlete.name_ar || athlete.name}</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #aaa;
    font-family: Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 36px;
    padding: 36px 20px;
  }
  .card {
    width: 420px;
    background: #fff;
    border-radius: 12px;
    overflow: hidden;
    box-shadow: 0 4px 20px rgba(0,0,0,0.25);
  }

  /* FRONT HEADER */
  .front-header {
    display: flex;
    align-items: stretch;
    height: 80px;
  }
  .hdr-logo {
    width: 80px;
    background: #fff;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 6px;
    flex-shrink: 0;
  }
  .hdr-logo img { width: 66px; height: 68px; object-fit: contain; }
  .hdr-title {
    flex: 1;
    background: #8B1A1A;
    color: #fff;
    text-align: center;
    font-size: 15px;
    font-weight: bold;
    line-height: 1.6;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 6px 4px;
  }

  /* FRONT NAME */
  .front-name {
    text-align: center;
    font-size: 19px;
    font-weight: bold;
    color: #000;
    padding: 12px 20px 8px;
  }

  /* FRONT BODY */
  /* LTR container: photo physically LEFT, info table physically RIGHT */
  .front-body {
    display: flex;
    align-items: flex-start;
    padding: 4px 14px 16px;
    gap: 14px;
    direction: ltr;
  }

  /* Photo col - LEFT */
  .photo-col {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
    flex-shrink: 0;
  }
  .photo-frame {
    width: 90px;
    height: 108px;
    background: #c5d8e4;
    border-radius: 3px;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .photo-frame img { width:100%; height:100%; object-fit:cover; object-position: top center; }
  .photo-placeholder { font-size:48px; color:#5b8fa8; }
  .qss-badge {
    width: 90px;
    background: #8B1A1A;
    color: #fff;
    font-size: 14px;
    font-weight: bold;
    text-align: center;
    padding: 4px;
    border-radius: 3px;
    letter-spacing: 1px;
  }

  /* Info table - RIGHT, RTL text flow */
  .info-table {
    flex: 1;
    direction: rtl;
  }
  .info-row {
    display: flex;
    align-items: baseline;
    padding: 4.5px 0;
    gap: 8px;
  }
  /* Label on RIGHT (first in RTL flow), grey */
  .lbl {
    font-size: 13px;
    font-weight: bold;
    color: #888;
    white-space: nowrap;
    flex-shrink: 0;
  }
  /* Value to LEFT of label */
  .val {
    font-size: 13px;
    color: #111;
    font-weight: 500;
    flex: 1;
    text-align: right;
  }

  /* BACK CARD */
  .back-header {
    background: #8B1A1A;
    color: #fff;
    text-align: center;
    font-size: 18px;
    font-weight: bold;
    padding: 10px;
  }
  .back-body {
    background: #fff;
    padding: 18px 16px 22px;
    direction: rtl;
  }
  /* LTR container: club logo LEFT, id block RIGHT */
  .back-top {
    display: flex;
    align-items: flex-start;
    direction: ltr;
    margin-bottom: 18px;
    gap: 10px;
  }
  .club-logo {
    width: 65px;
    height: 65px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }
  .club-logo img { width:100%; height:100%; object-fit:contain; }
  .id-block {
    flex: 1;
    direction: rtl;
    text-align: right;
  }
  .id-row {
    display: flex;
    align-items: baseline;
    gap: 8px;
    justify-content: flex-start;
  }
  .id-label {
    font-size: 13px;
    font-weight: bold;
    color: #888;
    white-space: nowrap;
  }
  .id-number {
    font-size: 13px;
    font-weight: bold;
    color: #111;
    direction: ltr;
  }
  .secretary {
    text-align: center;
    font-size: 13px;
    font-weight: bold;
    color: #111;
    line-height: 1.8;
    margin-bottom: 10px;
  }
  .sig-box {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 52px;
  }
  .sig-box img { height: 46px; object-fit: contain; }

  @media print {
    body { background: white; padding: 0; gap: 14mm; }
    .card { box-shadow: none; page-break-inside: avoid; break-inside: avoid; }
    .print-btn { display: none !important; }
  }
</style>
</head>
<body>

<!-- FRONT -->
<div class="card">
  <div class="front-header">
    <!-- QPC logo LEFT -->
    <div class="hdr-logo"><img src="${QPC}" alt="QPC"/></div>
    <div class="hdr-title">الاتحاد القطري لذوي<br/>الاحتياجات الخاصة</div>
    <!-- Qatar logo RIGHT -->
    <div class="hdr-logo"><img src="${QATAR}" alt="Qatar"/></div>
  </div>

  <div class="front-name">${athlete.name_ar || athlete.name}</div>

  <div class="front-body">
    <!-- Photo LEFT -->
    <div class="photo-col">
      <div class="photo-frame">
        ${photoSrc ? `<img src="${photoSrc}" alt="photo"/>` : `<div class="photo-placeholder">👤</div>`}
      </div>
      <div class="qss-badge">${athlete.qss_number || '00000'}</div>
    </div>

    <!-- Info RIGHT -->
    <div class="info-table">
      <div class="info-row"><div class="lbl">النادي</div><div class="val">${athlete.club || ''}</div></div>
      <div class="info-row"><div class="lbl">الوظيفة</div><div class="val">${desigAr}</div></div>
      <div class="info-row"><div class="lbl">الفئة</div><div class="val">${athlete.age_category || ''}</div></div>
      <div class="info-row"><div class="lbl">الصفة</div><div class="val">${residAr}</div></div>
      <div class="info-row"><div class="lbl">تاريخ الميلاد</div><div class="val">${athlete.dob || ''}</div></div>
      <div class="info-row"><div class="lbl">الموسم</div><div class="val">${SEASON}</div></div>
    </div>
  </div>
</div>

<!-- BACK -->
<div class="card">
  <div class="back-header">اللجنة الاولمبية القطرية</div>
  <div class="back-body">
    <div class="back-top">
      <!-- Club logo LEFT -->
      <div class="club-logo">
        ${athlete.club_logo ? `<img src="${athlete.club_logo}" alt="club"/>` : ''}
      </div>
      <!-- ID RIGHT -->
      <div class="id-block">
        <div class="id-row">
          <div class="id-label">الرقم الشخصي</div>
          <div class="id-number">${athlete.id_number || '—'}</div>
        </div>
      </div>
    </div>
    <div class="secretary">أمين السر العام للاتحاد القطرى<br/>للاحتياجات الخاصة</div>
    <div class="sig-box"><img src="${SIG}" alt="signature"/></div>
  </div>
</div>

<div class="print-btn" style="text-align:center">
  <button onclick="window.print()"
    style="padding:10px 34px;background:#8B1A1A;color:#fff;border:none;border-radius:8px;font-size:14px;cursor:pointer;font-family:Arial">
    🖨️ طباعة / Print
  </button>
</div>
</body>
</html>`

  return html
}

export default function AthleteCardButton({ athlete }) {
  function handleGenerate() {
    const html = generateAthleteCard(athlete)
    const win = window.open('', '_blank')
    win.document.write(html)
    win.document.close()
  }
  return (
    <button onClick={handleGenerate} className="action-btn"
      style={{ borderColor:'#8B1A1A', color:'#8B1A1A', padding:'5px 12px' }}
      onMouseEnter={e => { e.currentTarget.style.background='#fef2f2' }}
      onMouseLeave={e => { e.currentTarget.style.background='' }}>
      <i className="ti ti-id-badge" style={{ fontSize:14 }} /> Generate Card
    </button>
  )
}
